// ===== module imports (6.0.0; generated by build/convert-esm-pass2.mjs) =====
import { safeLog } from './03-memory-management.js';
import { doc, onSnapshot, setDoc } from './01-firebase-imports.js';
import { instanceId } from './02-dom-elements.js';
import { updateClock } from './10-clock-engine.js';
import { showUserMessage } from './19-visual-cues-and-files.js';
import { state } from './state.js';

// ============================================================
// V5.65.0: Quick Bell Broadcast Functions
// Sync quick bells across all logged-in devices for the same user
// ============================================================

/**
 * Send a quick bell broadcast to Firestore
 */
async function broadcastQuickBell(action, hours, minutes, seconds, sound, name, durationMs) {
    if (!state.userId || state.isUserAnonymous) {
        safeLog.log('[Broadcast] Cannot send - no user or anonymous');
        return;
    }
    
    const broadcastPath = `artifacts/${state.appId}/users/${state.userId}/quick_bell_broadcast/current`;
    safeLog.log('[Broadcast] Sending to path:', broadcastPath);
    
    try {
        const broadcastRef = doc(state.db, 'artifacts', state.appId, 'users', state.userId, 'quick_bell_broadcast', 'current');
        const broadcastData = {
            action: action, // 'start' or 'cancel'
            hours: hours || 0,
            minutes: minutes || 0,
            seconds: seconds || 0,
            sound: sound || 'ellisBell.mp3',
            name: name || 'Quick Bell',
            durationMs: durationMs || 0,
            timestamp: Date.now(),
            originInstance: instanceId
        };
        safeLog.log('[Broadcast] Data:', broadcastData);
        
        await setDoc(broadcastRef, broadcastData);
        safeLog.log(`[Broadcast] Successfully sent ${action} broadcast for "${name}"`);
    } catch (error) {
        console.error('[Broadcast] Error sending broadcast:', error);
    }
}

/**
 * Set up listener for incoming quick bell broadcasts
 * NOTE: This listener should be active regardless of whether broadcastEnabled is true
 * The toggle only affects SENDING, not RECEIVING
 */
function setupBroadcastListener() {
    if (!state.userId || state.isUserAnonymous) {
        safeLog.log('[Broadcast] Cannot set up listener - no user or anonymous');
        return;
    }
    
    // Clean up existing listener
    if (state.broadcastListenerUnsubscribe) {
        state.broadcastListenerUnsubscribe();
        state.broadcastListenerUnsubscribe = null;
    }
    
    const broadcastRef = doc(state.db, 'artifacts', state.appId, 'users', state.userId, 'quick_bell_broadcast', 'current');
    safeLog.log('[Broadcast] Setting up listener at path:', `artifacts/${state.appId}/users/${state.userId}/quick_bell_broadcast/current`);
    
    state.broadcastListenerUnsubscribe = onSnapshot(broadcastRef, (docSnap) => {
        safeLog.log('[Broadcast] Received snapshot, exists:', docSnap.exists());
        if (!docSnap.exists()) return;
        
        const data = docSnap.data();
        safeLog.log('[Broadcast] Snapshot data:', data);
        
        // Ignore broadcasts from this instance
        if (data.originInstance === instanceId) {
            safeLog.log('[Broadcast] Ignoring own broadcast (origin:', data.originInstance, ', this:', instanceId, ')');
            return;
        }
        
        // Ignore old broadcasts (more than 10 seconds old - increased from 5)
        const age = Date.now() - data.timestamp;
        if (age > 10000) {
            safeLog.log(`[Broadcast] Ignoring stale broadcast (${age}ms old)`);
            return;
        }
        
        // Prevent duplicate processing
        if (data.timestamp <= state.lastProcessedBroadcastTimestamp) {
            safeLog.log('[Broadcast] Ignoring already-processed broadcast');
            return;
        }
        state.lastProcessedBroadcastTimestamp = data.timestamp;
        
        safeLog.log(`[Broadcast] Processing ${data.action} broadcast for "${data.name}"`);
        
        if (data.action === 'start') {
            // Start the quick bell locally (without re-broadcasting)
            const now = new Date();
            state.quickBellEndTime = new Date(now.getTime() + data.durationMs);
            state.quickBellEndTime.bellName = data.name;
            state.quickBellEndTime.wasBroadcast = true; // Mark as broadcast-received
            state.quickBellSound = data.sound;
            document.getElementById('cancel-quick-bell-btn').classList.remove('hidden');
            updateClock();
        } else if (data.action === 'cancel') {
            // Cancel the quick bell locally
            state.quickBellEndTime = null;
            document.getElementById('cancel-quick-bell-btn').classList.add('hidden');
            updateClock();
        }
    }, (error) => {
        console.error('[Broadcast] Listener error:', error);
    });
    
    safeLog.log('[Broadcast] Listener set up successfully for user:', state.userId);
}

/**
 * Clean up broadcast listener
 */
function cleanupBroadcastListener() {
    if (state.broadcastListenerUnsubscribe) {
        state.broadcastListenerUnsubscribe();
        state.broadcastListenerUnsubscribe = null;
    }
}

/**
 * Toggle broadcast mode on/off
 */
function toggleBroadcastMode() {
    state.broadcastEnabled = !state.broadcastEnabled;
    updateBroadcastToggleUI();
    
    if (state.broadcastEnabled) {
        showUserMessage('📡 Broadcast ON - Quick bells will sync to all your devices');
    } else {
        showUserMessage('📡 Broadcast OFF - Quick bells only on this device');
    }
}

/**
 * Update the broadcast toggle button UI
 */
function updateBroadcastToggleUI() {
    const btn = document.getElementById('quick-bell-broadcast-toggle');
    if (!btn) return;
    
    if (state.broadcastEnabled) {
        btn.classList.remove('bg-gray-200', 'text-gray-500');
        btn.classList.add('bg-sky-500', 'text-white');
        btn.title = 'Broadcast to all devices (ON)';
    } else {
        btn.classList.remove('bg-sky-500', 'text-white');
        btn.classList.add('bg-gray-200', 'text-gray-500');
        btn.title = 'Broadcast to all devices (off)';
    }
}

// ============================================================
// END V5.65.0: Quick Bell Broadcast Functions
// ============================================================


// ===== module exports (6.0.0) =====
export {
    broadcastQuickBell,
    cleanupBroadcastListener,
    setupBroadcastListener,
    toggleBroadcastMode,
    updateBroadcastToggleUI,
};
